const mk = (title, topic, difficulty, neet) => ({
  id: slugify(title),
  title,
  topic,
  difficulty,
  freq: fq(title),
  neet,
  reported: REPORTED[title] || [],
  url: 'https://leetcode.com/problems/' + (URL_OVERRIDE[title] || slugify(title)) + '/',
  status: 'todo',
  confidence: 0,
  notes: '',
  lastPracticed: '',
})

